import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import type { Post, Comment } from '@/lib/types';

interface PageProps {
  params: Promise<{ id: string }>;
}

export async function generateStaticParams() {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=10');
  const posts: Post[] = await res.json();

  return posts.map((post) => ({
    id: post.id.toString(),
  }));
}

export const dynamicParams = true;

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { id } = await params;
  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`);

  if (!res.ok) {
    return { title: 'Post Not Found' };
  }

  const post: Post = await res.json();

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPost({ params }: PageProps) {
  const { id } = await params;

  try {
    const [postRes, commentsRes] = await Promise.all([
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
        next: { revalidate: 300 },
      }),
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
        next: { revalidate: 300 },
      }),
    ]);

    if (!postRes.ok) {
      notFound();
    }

    const post: Post = await postRes.json();
    const comments: Comment[] = await commentsRes.json();

    return (
      <article>
        <Link href="/blog">
          <button>&larr; Back</button>
        </Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}

import { NextRequest, NextResponse } from 'next/server';
import type { ApiPost } from '@/lib/types';

let posts: ApiPost[] = [
  { id: 1, title: 'First Post', content: 'This is the first post' },
  { id: 2, title: 'Second Post', content: 'This is the second post' },
];

export async function GET() {
  return NextResponse.json(posts);
}

export async function POST(request: NextRequest) {
  const body = await request.json();
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json(
      { error: 'Title and content are required' },
      { status: 400 },
    );
  }

  const newPost: ApiPost = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  posts.push(newPost);

  return NextResponse.json(newPost, { status: 201 });
}

import { NextRequest, NextResponse } from 'next/server';
import type { ApiPost } from '@/lib/types';

interface RouteParams {
  params: Promise<{ id: string }>;
}

export async function GET(
  _request: NextRequest,
  { params }: RouteParams,
) {
  const { id } = await params;
  const post: ApiPost = {
    id: parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(
  request: NextRequest,
  { params }: RouteParams,
) {
  const { id } = await params;
  const body = await request.json();
  const { title, content } = body;

  const updatedPost: ApiPost = {
    id: parseInt(id, 10),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(
  _request: NextRequest,
  { params }: RouteParams,
) {
  const { id } = await params;

  return NextResponse.json({
    message: `Post ${id} deleted successfully`,
  });
}
